8	import SwiftUI
9	
10	struct AlarmLevelWheelVerticalView: View {
11	
12	    private enum Consts {
13	        static let steps = 5
14	    }
15	
16	    let color: Color
17	    var alarmWheelModel: AlarmWheelModel
18	
19	    @State private var isLoaded = false
20	    @State private var disabled = false
21	
22	    var body: some View {
23	        ZStack {
24	            GeometryReader {
25	                let size = $0.size
26	                let padding = size.height / 2
27	                ScrollView(.vertical) {
28	                    LazyVStack(spacing: 0) {
29	                        ForEach(alarmWheelModel.values.indices, id: \.self) { index in
30	                            let remainder = index % Consts.steps
31	                            Divider()
32	                                .background(.gray)
33	                                .frame(width: 80, height: 1)
34	                                .overlay(alignment: .leading) {
35	                                    if remainder == 0 {
36	                                        Text(verbatim: "\(alarmWheelModel.formatted(index: index))")
37	                                            .font(.system(size: 12))
38	                                            .foregroundStyle(.textSecondary)
39	                                            .offset(x: 85)
40	                                    }
41	                                }
42	                                .padding(.vertical, 5)
43	                        }
44	                    }
45	                    .frame(width: size.width)
46	                    .scrollTargetLayout()
47	                }
48	                .scrollIndicators(.hidden)
49	                .scrollTargetBehavior(.viewAligned)
50	                .scrollPosition(
51	                    id: .init(
52	                        get: { isLoaded ? alarmWheelModel.values.firstIndex(where: { $0 <= alarmWheelModel.selectedValue }) : nil },
53	                        set: { newIndex in
54	                            if let newIndex, let value = alarmWheelModel.values[safe: newIndex], value != alarmWheelModel.selectedValue {
55	                                alarmWheelModel.selectedValue = value
56	                            }
57	                        }
58	                    )
59	                )
60	                .overlay(alignment: .center) {
61	                    Rectangle()
62	                        .foregroundStyle(color)
63	                        .frame(width: 100, height: 2)
64	                        .padding(.trailing, 20)
65	                        .padding(.top, 10)
66	                }
67	                .safeAreaPadding(.vertical, padding)
68	                .onAppear {
69	                    if !isLoaded {
70	                        isLoaded = true
71	                    }
72	                }
73	                .scrollDisabled(disabled)
74	                .sensoryFeedback(.impact, trigger: alarmWheelModel.selectedValue)
75	            }
76	        }
77	        .mask(
78	            LinearGradient(
79	                gradient: Gradient(colors: [.clear, .dark06, .dark06, .clear]),
80	                startPoint: .bottom,
81	                endPoint: .top
82	            )
83	        )
84	        .onChange(of: alarmWheelModel.selectedValue) { _, newValue in
85	            guard !disabled else { return }
86	            if newValue == alarmWheelModel.values.last {
87	                disabled = true
88	                withAnimation {
89	                    alarmWheelModel.selectedValue = alarmWheelModel.values[alarmWheelModel.values.count - 2]
90	                }
91	                Task { @MainActor in
92	                    disabled = false
93	                }
94	            }
95	        }
96	    }
97	}
